using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with a default resolver (handles any type at runtime)
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() â€” returns JsonTypeInfo<Person> directly, no cast needed
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized via typed metadata: {json}");

// 2) TryGetTypeInfo<T>() â€” check-without-throwing
//    With the default (reflection) resolver every type resolves, so Person succeeds.
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGet succeeded for {info!.Type.Name}");
}

// Now use a *source-gen* context that only knows about Person.
// Querying for a type it doesn't know (int) returns false â€” no exception.
var limited = new JsonSerializerOptions { TypeInfoResolver = AppJsonContext.Default };

if (limited.TryGetTypeInfo<int>(out JsonTypeInfo<int>? intInfo))
{
    Console.WriteLine($"TryGet succeeded for {intInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGet for Int32 returned false â€” metadata not available");
}

public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
internal partial class AppJsonContext : JsonSerializerContext;

